import { useRef, useState, useContext } from "react";
import * as FaIcons from "react-icons/fa";

import { ContextoGlobal } from '../../../contexts/variaveisGlobais'
import { FetchApi } from "../../../Controller/FetchApi";

const FaPlusCircle = <FaIcons.FaPlusCircle size = {40}/>


function HandleClientes(){
    const [exibirCampoBusca, setExibirCampoBusca] = useState(false);
    const { setClientes } = useContext(ContextoGlobal);
    const id = useRef('');
    const cpf = useRef('');
    const nome = useRef('');
    const endereco = useRef('');
    const cidade = useRef('');
    const data = useRef('');

    function handlerExibirBusca(){
        if(exibirCampoBusca){
            setExibirCampoBusca(false);
        }else{
            setExibirCampoBusca(true);
        }
    }

    async function filtroDeClientes(e){
        let parametrosDeBusca = '';
        if(id.current.value === ''){
            if(e.target.value.length > 2){
                parametrosDeBusca = '/clientes/'+cpf.current.value+','+nome.current.value+','+
                endereco.current.value+','+cidade.current.value+','+data.current.value;
            }else{
                return;
            }           
        }else{
            parametrosDeBusca = '/cliente/'+id.current.value;
        }
        
        setClientes(await FetchApi.consultaGet(parametrosDeBusca));
    }

    return (
        <div className="PainelDeControle">
            <div className=" flexNaoResponsivo espacoAntes">
                <div className="divFlex div-botao clicado espacoAntes padding5px">
                    <label>
                        NOVO CLIENTE
                    </label>
                    <div className="espacoAntes">
                        {FaPlusCircle}
                    </div>
                </div>
                <div  onClick={() => handlerExibirBusca()}  className={` ${exibirCampoBusca? 'clicado' : ''} `} className="campoDestacado">
                    <h4>Procurar algum cliente</h4>
                </div>
            </div>
            {exibirCampoBusca && 
                <div className="espacoAoRedor padding5px campoDestacado">
                    <div>
                        <input type='text' ref={id} id='filtroIdCliente' onChange={filtroDeClientes} className="form-control" placeholder="Id do Cliente"/>
                    </div>
                    <div>
                        <input type='text' ref={cpf} id='filtroCpfCliente' onChange={filtroDeClientes} className="form-control" placeholder="CPF ou CNPJ do Cliente"/>
                    </div>
                    
                    <div>
                        <input type='text' ref={nome} id='filtroNomeCliente' onChange={filtroDeClientes} onClick={(e) => e.target.select()} className='form-control' placeholder="Nome do Cliente"/>
                    </div>
                    <div>
                        <input type='text' ref={endereco} id='filtroEnderecoCliente' onChange={filtroDeClientes} onClick={(e) => e.target.select()} className='form-control' placeholder='Endereço' />
                    </div>
                    <div>
                        <input type='text' ref={cidade} id='filtroCidadeCliente' onChange={filtroDeClientes} onClick={(e) => e.target.select()} className='form-control' placeholder='Cidade' />
                    </div>
                    <div>    
                        <label>Data de algum evento</label>
                    </div>
                    <div>    
                        <input  ref={data} id='filtroDataUltimoEventoCliente' onChange={filtroDeClientes} className='form-control' type='date'/>
                    </div>
                </div>                
            }   
        </div>
    )
}

export default HandleClientes;
